const calculateComponentPremium = (type: string, count: number): number =>
  count === BLOCK_SIZE ? BLOCK_PREMIUM : count * (BASE_PREMIUMS[type] ?? 0);

export function processScenario(scenario: Scenario): ScenarioOutput {
  const results = scenario.steps.map((step) => {
    let basePremium = 0;

    const componentCounts = new Map<string, number>();
    for (const item of step.items) {
      if (COMPONENT_TYPES.has(item.type)) {
        componentCounts.set(item.type, (componentCounts.get(item.type) ?? 0) + 1);
      } else {
        basePremium += BASE_PREMIUMS[item.type] ?? 0;
      }
    }

    for (const [type, count] of componentCounts) {
      basePremium += calculateComponentPremium(type, count);
    }

    const premium = basePremium + PROCESSING_FEE;
    return { premium };
  });
  return { results };
}

